// Calculate running status
const data = $input.first().json;

const totalLines = parseInt(data.total_lines) || 0;
const numberOfEntries = parseInt(data.number_of_entries) || 0;
const numberOfOutputs = parseInt(data.number_of_outputs) || 0;

// running = NOT (entries == outputs == total_lines)
const running = !(numberOfEntries === numberOfOutputs && numberOfEntries === totalLines);

// Structured logging
console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'cc_status_calculated',
  total_lines: totalLines,
  entries: numberOfEntries,
  outputs: numberOfOutputs,
  running: running
}));

return {
  statusCode: 200,
  body: {
    running: running,
    total_lines: totalLines,
    number_of_entries: numberOfEntries,
    number_of_outputs: numberOfOutputs
  }
};
